import{_ as l,o as a,c as r,ae as e}from"./chunks/framework.DAK3ioSj.js";const g=JSON.parse('{"title":"Skill 召回（Recall / Routing）","description":"","frontmatter":{},"headers":[],"relativePath":"radar/category-02-recall.md","filePath":"radar/category-02-recall.md"}'),o={name:"radar/category-02-recall.md"};function i(n,t,d,s,h,k){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="skill-召回-recall-routing" tabindex="-1">Skill 召回（Recall / Routing） <a class="header-anchor" href="#skill-召回-recall-routing" aria-label="Permalink to &quot;Skill 召回（Recall / Routing）&quot;">​</a></h1><blockquote><p><strong>成熟度</strong>: 🟢 成熟期 · <strong>综合评分</strong>: <strong>0.65</strong></p><p><strong>业界判断</strong>：SkillRouter 在 80K 池上达 74% Hit@1 并工程化，AgentSkillOS 提供 DAG 编排，基础问题已有可工程化方案。这是六个阶段中<strong>最成熟</strong>的赛道。</p></blockquote><hr><h2 id="业界代表产品" tabindex="-1">业界代表产品 <a class="header-anchor" href="#业界代表产品" aria-label="Permalink to &quot;业界代表产品&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产品</th><th>来源</th><th>核心路径</th><th>关键数字</th></tr></thead><tbody><tr><td><a href="./tech-skillrouter.html">SkillRouter</a></td><td>学术</td><td>双编码器 + 重排，全文检索</td><td><strong>80K 池 74% Hit@1</strong>，1.2B 少 13× 参数、快 5.8×</td></tr><tr><td><a href="./tech-agentskillos.html">AgentSkillOS</a></td><td>学术</td><td>Capability Tree + DAG</td><td>200–200K 规模逼近理想</td></tr><tr><td><a href="./tech-skillnet.html">SkillNet</a></td><td>浙大 NLP (735 ★)</td><td>Ontology 三层架构</td><td><strong>200K+ Skill 仓库</strong></td></tr><tr><td><a href="./tech-skillrouter-org.html">SkillRouter.org</a></td><td>商业（早期）</td><td>MCP 路由服务</td><td>落地页阶段，无公开评测</td></tr><tr><td><strong><a href="./tech-skillret.html">SkillRet</a></strong> ★</td><td>学术</td><td>Skill 检索 benchmark</td><td>17,810 Skill / NDCG@10 +13.1</td></tr></tbody></table><hr><h2 id="行业关键发现" tabindex="-1">行业关键发现 <a class="header-anchor" href="#行业关键发现" aria-label="Permalink to &quot;行业关键发现&quot;">​</a></h2><h3 id="🟢-推翻-标题-简介够用-的设计共识" tabindex="-1">🟢 推翻&quot;标题 + 简介够用&quot;的设计共识 <a class="header-anchor" href="#🟢-推翻-标题-简介够用-的设计共识" aria-label="Permalink to &quot;🟢 推翻&quot;标题 + 简介够用&quot;的设计共识&quot;">​</a></h3><p>SkillRouter 在 ~80K Skill 池上<strong>隐藏 Skill body 后路由准确率暴跌 31-44 个百分点</strong>。</p><blockquote><p>两本书封面都写&quot;数据可视化指南&quot;，但一本教 Python Matplotlib，另一本教 Excel 图表 —— 不翻开内容根本分不清。</p></blockquote><p><strong>关键意义</strong>不在 74% 这个数字本身，而在证明了<strong>全文检索是不可绕过的必要条件</strong> —— 改变了所有 Agent 框架的路由层设计。</p><h3 id="🟡-多-skill-编排-从单调用到-dag" tabindex="-1">🟡 多 Skill 编排：从单调用到 DAG <a class="header-anchor" href="#🟡-多-skill-编排-从单调用到-dag" aria-label="Permalink to &quot;🟡 多 Skill 编排：从单调用到 DAG&quot;">​</a></h3><p>AgentSkillOS 把 Skill 依赖关系建模为有向无环图，能并行的并行、必须串行的串行。<strong>DAG 执行显著优于简单逐个调用</strong>，是首个系统方案。</p><p>但 DAG 假设<strong>依赖关系可在执行前静态确定</strong> —— 动态依赖场景（&quot;第二步选择取决于第一步结果&quot;）未覆盖。</p><hr><h2 id="行业痛点" tabindex="-1">行业痛点 <a class="header-anchor" href="#行业痛点" aria-label="Permalink to &quot;行业痛点&quot;">​</a></h2><h3 id="🟢-大规模-skill-池路由-基本已解" tabindex="-1">🟢 大规模 Skill 池路由（基本已解） <a class="header-anchor" href="#🟢-大规模-skill-池路由-基本已解" aria-label="Permalink to &quot;🟢 大规模 Skill 池路由（基本已解）&quot;">​</a></h3><p>SkillRouter 工程化方案可部署消费级硬件。</p><h3 id="🔴-skill-功能相似带来的混淆" tabindex="-1">🔴 Skill 功能相似带来的混淆 <a class="header-anchor" href="#🔴-skill-功能相似带来的混淆" aria-label="Permalink to &quot;🔴 Skill 功能相似带来的混淆&quot;">​</a></h3><p>社区仓库中<strong>大量 Skill 名称和目的相似</strong> —— 仅用 name+description 路由准确率下降 31-44pp。识别出&quot;谁和谁相似&quot;之后怎么办？<strong>没有产品做自动合并相似 Skill</strong>。</p><h3 id="⚪-用户不知道有-skill-可用" tabindex="-1">⚪ 用户不知道有 Skill 可用 <a class="header-anchor" href="#⚪-用户不知道有-skill-可用" aria-label="Permalink to &quot;⚪ 用户不知道有 Skill 可用&quot;">​</a></h3><p>所有路由研究都假设用户&quot;知道应该去找 Skill&quot;。但实际中用户可能压根没想到&quot;这件事有 Skill 能帮我&quot;。<strong>完全空白</strong>。</p><h3 id="🟡-多-skill-动态编排" tabindex="-1">🟡 多 Skill 动态编排 <a class="header-anchor" href="#🟡-多-skill-动态编排" aria-label="Permalink to &quot;🟡 多 Skill 动态编排&quot;">​</a></h3><p>复杂任务需要组合三个 Skill，但不知道<strong>先用哪个、后用哪个、哪些可以同时用</strong>。AgentSkillOS DAG 是初步方案，<strong>动态依赖场景未覆盖</strong>。</p>',24)])])}const u=l(o,[["render",i]]);export{g as __pageData,u as default};
